    window.__yieldStartupErrors = [];
    function showStartupError(message) {
      window.__yieldStartupErrors.push(message);
      try {
        let box = document.getElementById('startupErrorBanner');
        if (!box) {
          box = document.createElement('div');
          box.id = 'startupErrorBanner';
          box.style.cssText = 'position:fixed;z-index:999999;top:12px;left:12px;right:12px;background:#fff4f4;color:#7f1d1d;border:1px solid #fca5a5;border-radius:8px;padding:12px 14px;font:13px/1.4 Arial,sans-serif;box-shadow:0 10px 24px rgba(0,0,0,.15);white-space:pre-wrap;';
          document.body.appendChild(box);
        }
        box.textContent = `Dashboard startup error:\n${window.__yieldStartupErrors.join('\n')}`;
      } catch {}
    }
    window.addEventListener('error', event => {
      showStartupError(`${event.message || 'Script error'}${event.filename ? ` at ${event.filename}:${event.lineno || ''}:${event.colno || ''}` : ''}`);
    });
    window.addEventListener('unhandledrejection', event => {
      showStartupError(event.reason?.stack || event.reason?.message || String(event.reason || 'Unhandled promise rejection'));
    });
