      if (raw.includes('avg') || raw.includes('average') || raw.includes('ending') || raw.includes('balance') || raw.includes('asset') || raw.includes('liab') || raw.includes('capital')) return 'Balance';
      return raw === 'balance' ? 'Balance' : '';
