        return `<button class="org-picker-row${active}${structural}" type="button" data-org-value="${printEscape(row.value)}" data-selectable="${row.selectable ? '1' : '0'}" style="padding-left:${12 + row.depth * 18}px">${toggle}<span class="org-picker-name">${printEscape(row.label)}</span><span class="org-picker-meta">${printEscape(meta)}</span></button>`;
