          commercial: totalCodes(monthRows, commercialCodes, 'Ending Balance'),
          mortgage: totalCodes(monthRows, mortgageCodes, 'Ending Balance'),
          coreDeposits: totalCode(monthRows, 203999, 'Ending Balance') - totalCodes(monthRows, highWealthCodes, 'Ending Balance') - totalCodes(monthRows, wholesaleDepositCodes, 'Ending Balance'),
          wholesaleFunding
