      const max = Math.max(...vals.flatMap(v=>series.map(s=>v[s[0]])), 1), w=900,h=310,p=48;
      const x = i => p + i*(w-p*2)/(vals.length-1 || 1), y = v => h-p - (v/max)*(h-p*2);
      const line = kind => vals.map((v,i)=>`${i?'L':'M'}${x(i)},${y(v[kind])}`).join(' ');
      return `<svg viewBox="0 0 ${w} ${h}" width="100%" height="100%" role="img"><g>${[0,.25,.5,.75,1].map(t=>`<line x1="${p}" x2="${w-p}" y1="${y(max*t)}" y2="${y(max*t)}" stroke="#eee5d8"/><text x="8" y="${y(max*t)+4}" fill="#667085" font-size="12">${money(max*t)}</text>`).join('')}</g>${series.map(s=>`<path d="${line(s[0])}" fill="none" stroke="${s[1]}" stroke-width="5" stroke-linecap="round" stroke-linejoin="round"/>`).join('')}<g>${vals.map((v,i)=>`${series.map(s=>`<circle cx="${x(i)}" cy="${y(v[s[0]])}" r="4.5" fill="${s[1]}"/>`).join('')}<text x="${x(i)}" y="${h-12}" text-anchor="middle" fill="#18212d" font-size="12" font-weight="800">${v.label}</text>`).join('')}</g></svg>`;
