        'Securities': 'Total Security Income',
        'FHLB Stock': 'Total FHLB Stock',
        'Total Investments': 'Total Investment Income',
        'Total Commercial Bank': 'Total Commercial Bank Income',
        '1-4 Family Investment Loans': 'Total 1-4 Family Investment Loan Income',
        'Portfolio Mortgage Loans': 'Total Portfolio Mortgage Loan Income',
        'Purchased Mortgage Loans': 'Total Purchased Mortgage Loan Income',
        'Net Loans Purchased': 'Total Net Loans Purchased Income',
        'Held For Sale': 'Total HFS Income',
        'Participations': 'Total Participation Income',
        'Total Mortgage Bank Loans': 'Total Mortgage Bank Income',
        'Earning Assets': 'Total Interest Income',
        'Net Interest Income/ Spread': 'Net Interest Income',
        'Retail Interest Bearing Deposits': 'Retail Interest Bearing Deposit Expense',
        'Wholesale Funding': 'Wholesale Funding Expense',
        'Total Interest Bearing Deposits': 'Total Deposits Expense',
