      const prevDiff = displayBalanceValue(lineMeasure(lineByLabel('Total Assets'), prev)) - displayBalanceValue(lineMeasure(lineByLabel('Total Liabilities and Capital'), prev));
      const curIncomeDiff = lineMeasure(lineByLabel('Net Income'), cur).inc - netIncomeControlValue(cur);
