        const displayKey = line.label ? categoryKey(line.label).toLowerCase() : '';
        if (line.label && !isFrozenStatementLabel(line.label) && !momAlwaysDisplay.has(displayKey)) return '';
        const c = statementPeriodLineMeasure(line, curDates);
