        if (isBranchFiltered() && !line.branchOnly && !statementMeasureHasValue(c, p)) return '';
        const cls = statementRowClass(line);
        const hiddenChildren = nonDuplicatedDrillChildren(line.label, isBaseVisibleMomLine);
        const accountDrill = drillAccountsForLine(line);
        const drill = hiddenChildren.length ? hiddenChildren : accountDrill;
        const key = `ytd-statement-${idx}`;
        const displayLabel = accountRollupDisplayLabel(line.label);
        const icon = drill.length ? `<button class="drill-btn" type="button" data-ytd-statement-key="${key}" title="Drill into ${displayLabel}">${expandedYtdStatement.has(key) ? '-' : '+'}</button>` : `<span style="display:inline-block;width:26px"></span>`;
        const main = `<tr${cls}><td class="line-label" style="padding-left:7px">${icon}${displayLabel}</td>${renderMeasureCells(c,p)}</tr>`;
        if (!expandedYtdStatement.has(key)) return main;
        const detail = hiddenChildren.length
