      const curDiff = displayBalanceValue(statementPeriodLineMeasure(totalAssetsLine, curDates)) - displayBalanceValue(statementPeriodLineMeasure(totalLiabilitiesCapitalLine, curDates));
      const prevDiff = displayBalanceValue(statementPeriodLineMeasure(totalAssetsLine, compareDates, compareBudget)) - displayBalanceValue(statementPeriodLineMeasure(totalLiabilitiesCapitalLine, compareDates, compareBudget));
      const netIncomeLine = lineByLabel('Net Income');
