        const displayLabel = accountRollupDisplayLabel(line.label);
        const icon = drill.length ? `<button class="drill-btn" type="button" data-report-key="${key}" title="Drill into ${printEscape(displayLabel)}">${expandedReport.has(key) ? '-' : '+'}</button>` : `<span style="display:inline-block;width:26px"></span>`;
