      const activeReviewGroup = detailReviewGroups[active] || detailReviewGroup || 'var';
      document.querySelectorAll('[data-report-tab]').forEach(btn => btn.classList.toggle('active', btn.dataset.reportTab === active));
      document.querySelectorAll('.report-panel').forEach(panel => panel.classList.toggle('active', panel.id === active));
      document.querySelectorAll('[data-detail-family]').forEach(group => group.classList.toggle('active', group.dataset.detailFamily === family));
      document.querySelectorAll('[data-detail-review-group]').forEach(group => group.classList.toggle('active', group.dataset.detailReviewGroup === activeReviewGroup));
      document.querySelectorAll('[data-detail-review-group-btn]').forEach(btn => btn.classList.toggle('active', btn.dataset.detailReviewGroupBtn === activeReviewGroup));
      document.querySelectorAll('.review-global-control').forEach(control => control.classList.remove('open'));
      const compareControl = $('reviewCompareControl');
      const budgetControl = $('reviewBudgetControl');
      const showCompare = activeTabId() === 'reportingTab' && ['varianceBalanceSheetReport','varianceIncomeStatementReport'].includes(active);
      const showBudget = activeTabId() === 'reportingTab' && ['budgetToActualBalanceSheetReport','budgetToActualIncomeStatementReport','budgetToActualIncomeStatementYtdReport'].includes(active);
      const showAttributionMom = activeTabId() === 'reportingTab' && active === 'attributionMomReport';
      const showAttributionQoq = activeTabId() === 'reportingTab' && active === 'attributionQoqReport';
      $('overviewCompareControl')?.classList.toggle('open', activeTabId() === 'overviewTab');
      $('momCompareControl')?.classList.toggle('open', activeTabId() === 'momTab');
      $('qoqCompareControl')?.classList.toggle('open', activeTabId() === 'qoqTab');
      $('periodCompareControl')?.classList.toggle('open', activeTabId() === 'comparisonTab' || activeTabId() === 'ytdStatementTab');
      $('budgetLeftControl')?.classList.toggle('open', activeTabId() === 'budgetTab');
