        if (ctx.mode === 'bta') {
          const actual = detailReviewMeasureForLine(line, ctx, 'actual');
          const budget = detailReviewMeasureForLine(line, ctx, 'budget');
          const actualValue = detailReviewMeasureValue(actual, ctx.type, line);
          const budgetValue = detailReviewMeasureValue(budget, ctx.type, line);
          return actualValue === '' || budgetValue === '' ? '' : actualValue - budgetValue;
        }
        const current = detailReviewMeasureForLine(line, ctx, 'actual');
