      const elapsedMonths = end.getMonth() - qStartMonth;
      const priorQStart = new Date(end.getFullYear(), qStartMonth - 3, 1);
      const priorQEnd = monthEnd(priorQStart.getFullYear(), priorQStart.getMonth() + 2);
      const pyEndIso = isoDate(pyEnd);
