      renderPeriodTable('ytdHead', 'ytdRows', 'YIELD STATEMENT - YEAR TO DATE', ytdCurrentLabel, ytdCompareLabel, ytdVarianceLabel, ytdRows, 'Actual', ytdCompareSource, ytdContext);
