        'detail-var-is': {key:'var-is', mode:'variance', type:'income', title:'Variance Report - Income Statement', headId:'varianceIncomeStatementHead', bodyId:'varianceIncomeStatementRows', labelId:'varianceIncomeStatementLabel', sheetName:'Var IS'},
        'detail-bta-bs': {key:'bta-bs', mode:'bta', type:'balance', title:'Budget to Actual - Balance Sheet', headId:'budgetToActualBalanceSheetHead', bodyId:'budgetToActualBalanceSheetRows', labelId:'budgetToActualBalanceSheetLabel', sheetName:'BtA BS'},
        'detail-bta-is': {key:'bta-is', mode:'bta', type:'income', title:'Budget to Actual - Income Statement', headId:'budgetToActualIncomeStatementHead', bodyId:'budgetToActualIncomeStatementRows', labelId:'budgetToActualIncomeStatementLabel', sheetName:'BtA IS'},
