    function renderRepositoryFolder() {
      if (!$('repositoryFolderLabel')) return;
      $('repositoryFolderLabel').textContent = repositoryFolderSettings.label || defaultRepositoryFolder.label;
      $('repositoryFolderPath').textContent = repositoryFolderSettings.selectedName
        ? `Browser-selected: ${repositoryFolderSettings.selectedName} | Expected default: ${defaultRepositoryFolder.path}`
        : defaultRepositoryFolder.path;
      const activeStatus = importPersistenceStatus && importPersistenceStatus !== 'No saved browser imports loaded.'
        ? importPersistenceStatus
        : '';
      const selectedNote = repositoryFolderSettings.selectedName
        ? ` Browser-selected folder is active when permission is available; expected default is ${defaultRepositoryFolder.path}.`
        : '';
      $('repositoryFolderNote').textContent = activeStatus || `${repositoryFolderSettings.note || defaultRepositoryFolder.note}${selectedNote}`;
    }

    function renderBudgetFolder() {
      if (!$('budgetFolderLabel')) return;
      $('budgetFolderLabel').textContent = budgetFolderSettings.label || defaultBudgetFolder.label;
      $('budgetFolderPath').textContent = budgetFolderSettings.selectedName
        ? `Browser-selected: ${budgetFolderSettings.selectedName} | Expected default: ${defaultBudgetFolder.path}`
        : defaultBudgetFolder.path;
      const selectedNote = budgetFolderSettings.selectedName
        ? ` Browser-selected folder is active when permission is available; expected default is ${defaultBudgetFolder.path}.`
        : '';
      $('budgetFolderNote').textContent = `${budgetFolderSettings.note || defaultBudgetFolder.note}${selectedNote}`;
      const audit = lastBudgetLoadAudit || {};
      const auditText = audit.rows
        ? ` Source: ${audit.source}; ${Number(audit.rows || 0).toLocaleString()} rows; versions: ${(audit.versions || []).map(budgetVersionDisplayName).join(', ') || 'none'}.`
        : '';
      const warningText = audit.warningDetails?.length
        ? ` Warnings: ${audit.warningDetails.join(' | ')}`
        : '';
      $('budgetFolderStatus').textContent = `${budgetCacheStatus}${auditText}${warningText}`;
      renderApprovedBudgetOptions();
    }

    function renderApprovedBudgetOptions() {
      const container = $('approvedBudgetOptions');
      if (!container) return;
      const versions = budgetVersions();
      if (!versions.length) {
        container.innerHTML = '<div class="approved-budget-empty">Load the Budget tab or select the Budget folder to choose an approved version.</div>';
      } else {
        container.innerHTML = versions.map(version => `
          <label class="approved-budget-option">
            <input type="radio" name="approvedBudgetVersion" value="${printEscape(version)}" ${version === approvedBudgetVersion ? 'checked' : ''} />
            ${printEscape(budgetVersionDisplayName(version))}
          </label>
        `).join('');
      }
      if ($('approvedBudgetStatus')) {
        $('approvedBudgetStatus').textContent = approvedBudgetStatus || 'No approved budget committed yet.';
      }
    }

