          OrganizationKey:toNumber(row.OrganizationKey),
          OrganizationParentKey:toNumber(row.OrganizationParentKey),
          OrganizationName:String(row.OrganizationName || ''),
          UnaryOper:String(row.UnaryOper || '+'),
          SortOrder:toNumber(row.SortOrder),
