    $('printBtn')?.addEventListener('click', () => {
      const options = $('printOptions');
      const isOpen = options.classList.toggle('open');
      $('printBtn').setAttribute('aria-expanded', isOpen ? 'true' : 'false');
    });
    $('settingsBtn')?.addEventListener('click', () => activateTab('settingsTab'));
    $('toggleBrandingBtn')?.addEventListener('click', () => {
      const panel = $('brandingPanel');
      const isCollapsed = panel.classList.toggle('collapsed');
      $('toggleBrandingBtn').textContent = isCollapsed ? 'Show branding' : 'Hide branding';
    });
    $('bankNameInput')?.addEventListener('input', e => {
      brandSettings.name = e.target.value.trim() || defaultBrand.name;
      saveBrandSettings();
      applyBranding();
      renderMomStatement();
      renderQoqStatement();
    });
    $('logoInput')?.addEventListener('change', e => {
      const file = e.target.files?.[0];
      if (!file) return;
      const reader = new FileReader();
      reader.onload = () => {
        brandSettings.logo = String(reader.result || '') || defaultBrand.logo;
        saveBrandSettings();
        applyBranding();
      };
      reader.readAsDataURL(file);
      e.target.value = '';
    });
    $('resetBrandBtn')?.addEventListener('click', resetBranding);
    $('saveQuickMappingsBtn')?.addEventListener('click', saveSelectedQuickMappings);
    $('removeQuickMappingsBtn')?.addEventListener('click', () => removeQuickMappings(selectedQuickMappingAccounts()));
    $('exportQuickMappingsBtn')?.addEventListener('click', exportQuickMappings);
    $('quickMappingSelectAll')?.addEventListener('change', e => {
      document.querySelectorAll('[data-quick-map-account]').forEach(input => input.checked = e.target.checked);
    });
    $('saveBudgetMappingsBtn')?.addEventListener('click', saveSelectedBudgetMappings);
    $('ignoreBudgetMappingsBtn')?.addEventListener('click', ignoreSelectedBudgetMappings);
    $('removeBudgetMappingsBtn')?.addEventListener('click', removeSelectedBudgetMappings);
