    $('hierarchyCollapseAll')?.addEventListener('click', () => setHierarchyExpandedState(false));
    $('hierarchyAddChild')?.addEventListener('click', addHierarchyChild);
    $('hierarchyDeleteSelected')?.addEventListener('click', deleteHierarchyNode);
    function syncPrintSubgroupCheckboxes() {
      document.querySelectorAll('[data-print-subgroup]').forEach(group => {
        const children = [...document.querySelectorAll(`[data-print-subparent="${group.dataset.printSubgroup}"]`)];
        const checked = children.filter(child => child.checked).length;
        group.checked = children.length > 0 && checked === children.length;
        group.indeterminate = checked > 0 && checked < children.length;
      });
    }
    function syncPrintGroupCheckboxes() {
      syncPrintSubgroupCheckboxes();
      document.querySelectorAll('[data-print-group]').forEach(group => {
        const children = [...document.querySelectorAll(`[data-print-parent="${group.dataset.printGroup}"]`)];
        const checked = children.filter(child => child.checked).length;
        group.checked = children.length > 0 && checked === children.length;
        group.indeterminate = checked > 0 && checked < children.length;
      });
    }
    document.querySelectorAll('[data-print-group]').forEach(group => {
      group.addEventListener('change', () => {
        document.querySelectorAll(`[data-print-parent="${group.dataset.printGroup}"]`).forEach(child => {
          child.checked = group.checked;
        });
        document.querySelectorAll(`[data-print-subgroup-parent="${group.dataset.printGroup}"]`).forEach(child => {
          child.checked = group.checked;
          child.indeterminate = false;
        });
        syncPrintGroupCheckboxes();
      });
    });
    document.querySelectorAll('[data-print-subgroup]').forEach(group => {
      group.addEventListener('change', () => {
        document.querySelectorAll(`[data-print-subparent="${group.dataset.printSubgroup}"]`).forEach(child => {
          child.checked = group.checked;
        });
        syncPrintGroupCheckboxes();
      });
    });
    document.querySelectorAll('[data-print-section]').forEach(input => {
      input.addEventListener('change', syncPrintGroupCheckboxes);
    });
    syncPrintGroupCheckboxes();
    $('printSelectAll')?.addEventListener('click', () => {
      document.querySelectorAll('[data-print-section]').forEach(input => input.checked = true);
      syncPrintGroupCheckboxes();
    });
    $('printSelectedBtn')?.addEventListener('click', async () => {
      const sections = selectedPrintSections();
      if (!sections.length) {
        alert('Choose at least one report to print.');
        return;
      }
      $('printOptions').classList.remove('open');
      $('printBtn').setAttribute('aria-expanded', 'false');
      const btn = $('printSelectedBtn');
      const savedText = btn?.textContent || '';
      if (btn) {
        btn.disabled = true;
        btn.textContent = 'Preparing...';
      }
      const ready = await ensureBudgetForPrintSections(sections).catch(err => {
        alert('Budget load failed before print: ' + err.message);
        return false;
      });
      if (!ready) {
        if (btn) {
          btn.disabled = false;
          btn.textContent = savedText;
        }
        return;
      }
      buildPrintReport(sections);
      printReportReady = true;
      if (btn) {
        btn.disabled = false;
        btn.textContent = savedText;
      }
      window.print();
    });
    $('exportExcelBtn')?.addEventListener('click', () => {
      $('printOptions').classList.remove('open');
      $('printBtn').setAttribute('aria-expanded', 'false');
      exportSelectedBranchExcel().catch(err => alert('Excel export failed: ' + err.message));
    });
    $('chooseSettingsFolderBtn')?.addEventListener('click', () => {
      chooseSettingsFolder()
        .catch(err => {
          if (err?.name !== 'AbortError') alert('Settings folder selection failed: ' + err.message);
        });
    });
    $('saveSharedHierarchyFromEditorBtn')?.addEventListener('click', () => {
      saveSharedHierarchyFromUi().catch(err => alert('Shared workbook save failed: ' + err.message));
    });
    $('chooseRepositoryFolderBtn')?.addEventListener('click', () => {
      chooseRepositoryFolder()
        .then(() => loadExternalRepositoryData({requestPermission:true, force:true}))
        .then(loaded => { if (loaded) alert('Input Files folder loaded.'); })
        .catch(err => {
          if (err?.name === 'AbortError') return;
          alert('Input Files folder selection failed: ' + err.message);
          $('externalFolderInput')?.click();
        });
    });
    $('chooseBudgetFolderBtn')?.addEventListener('click', () => {
      chooseBudgetFolder()
        .then(() => loadBudgetRepositoryData({requestPermission:true, force:true}))
        .then(loaded => { if (loaded) showBudgetLoadedPopup('choose-folder'); })
        .catch(err => {
          if (err?.name === 'AbortError') return;
          $('budgetFolderInput')?.click();
        });
    });
    $('commitApprovedBudgetBtn')?.addEventListener('click', () => {
      commitApprovedBudgetFromUi().catch(err => alert('Approved budget commit failed: ' + err.message));
    });
    document.addEventListener('click', e => {
      const printMenu = $('printMenu');
      if (printMenu && !printMenu.contains(e.target)) {
        $('printOptions').classList.remove('open');
        $('printBtn').setAttribute('aria-expanded', 'false');
      }
    });
    window.addEventListener('beforeprint', () => {
      if (printReportReady) {
        printReportReady = false;
        return;
      }
      buildPrintReport();
    });
    applyBranding();
    renderRepositoryFolder();
    renderBudgetFolder();
    renderSharedHierarchyWorkbookStatus();
    function runDeferredStartupLoads() {
      scheduleSharedHierarchyStartupLoad();
      restoreFullBudgetCache({renderAfter:false}).then(loaded => {
        if (!loaded) return;
        renderBudgetFolder();
        populateBudgetVersionFilter();
        populatePeriodCompareFilter();
        if (activeTabId() === 'comparisonTab') renderComparisons();
        if (activeTabId() === 'ytdStatementTab') renderYtdStatement();
      }).catch(err => {
        budgetCacheStatus = `Could not restore saved budget cache: ${err.message}`;
        renderBudgetFolder();
      });
    }
    function scheduleDeferredStartupLoads(afterInitialData) {
      const start = () => {
        if ('requestIdleCallback' in window) {
          requestIdleCallback(runDeferredStartupLoads, {timeout: 2500});
        } else {
          setTimeout(runDeferredStartupLoads, 250);
        }
      };
      afterInitialData.finally(start);
    }
    const initialDashboardLoad = loadInitialDashboardData().catch(async err => {
      importPersistenceStatus = `Startup data load failed: ${err.message}`;
      renderLoadTestDiagnostics();
      try {
        await loadEmbeddedFallbackData('Historical GL dataset');
      } catch (fallbackErr) {
        importPersistenceStatus = `Startup fallback data load failed: ${fallbackErr.message}`;
        renderLoadTestDiagnostics();
      }
    });
    scheduleDeferredStartupLoads(initialDashboardLoad);

